package main

import (
	"encoding/gob"
	"fmt"
	"io/ioutil"
	"log"
	"os"
	"path/filepath"

	"github.com/gorilla/sessions"
)

type Session struct {
	ID       string `json:"id"`
	Prefs    map[string]string `json:"prefs"`
	Permissions []string `json:"permissions"`
}

func main() {
	gob.Register(Session{})

	store := sessions.NewFilePersistStore("sessions", filepath.Join(os.TempDir(), "sessions"))
	sessionManager := sessions.New(store)

	userID := "12345"
	prefs := map[string]string{"lang": "en"}
	permissions := []string{"read", "write"}

	session, _ := sessionManager.Get("session")
	if session == nil {
		session = &Session{ID: userID}
	} else {
		session.Values["id"] = userID
	}

	session.Values["prefs"] = prefs
	session.Values["permissions"] = permissions

	err := session.Save()
	if err != nil {
		log.Fatal(err)
	}

	fmt.Println(session.Values)

	file, _ := ioutil.TempFile("", "session")
	defer os.Remove(file.Name())

	encoder := gob.NewEncoder(file)
	err = encoder.Encode(session)
	if err != nil {
		log.Fatal(err)
	}
	file.Close()

	newSession, err := loadSession(file.Name())
	if err != nil {
		log.Fatal(err)
	}

	fmt.Println(newSession.Values)

	os.Remove(file.Name())
}

func loadSession(filename string) (*sessions.Session, error) {
	file, err := os.Open(filename)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	decoder := gob.NewDecoder(file)
	session := &sessions.Session{}
	err = decoder.Decode(session)
	if err != nil {
		return nil, err
	}

	return sessionManager.Get("session"), nil
}